package main

import "fmt"

// ---- Constants ----
const Pi = 3.14159
const MaxPlayers = 10
const AppName = "Go Game"

// ---- Multiple constants ----
const (
    StatusOK  = 200
    StatusNotFound = 404
    StatusInternalError = 500
)

// ---- iota: auto-incrementing constants ----
enum Direction {
    Up
    Down
    Left
    Right
}

// ---- iota with explicit values ----
const (
    _ = iota // 0 (ignored)
    Gold
    Silver
    Bronze
)

// ---- iota with expression ----
const (
    _ = iota
    KB = 1 << (10 * iota)  // 1 << (10*1) = 1024
    MB = 1 << (10 * iota)  // 1 << (10*2) = 1048576
    GB = 1 << (10 * iota)  // 1 << (10*3) = 1073741824
)

func main() {
    // ---- Constants ----
    fmt.Println("Pi:", Pi)
    fmt.Println("Max Players:", MaxPlayers)
    fmt.Println("App:", AppName)

    // ---- Status codes ----
    fmt.Println("OK:", StatusOK)
    fmt.Println("Not Found:", StatusNotFound)
    fmt.Println("Internal Error:", StatusInternalError)

    // ---- Directions ----
    fmt.Println("Up:", Up)
    fmt.Println("Down:", Down)
    fmt.Println("Left:", Left)
    fmt.Println("Right:", Right)

    // ---- iota values ----
    fmt.Println("Gold:", Gold)
    fmt.Println("Silver:", Silver)
    fmt.Println("Bronze:", Bronze)

    // ---- Byte sizes ----
    fmt.Println("KB:", KB)
    fmt.Println("MB:", MB)
    fmt.Println("GB:", GB)

    // ---- Constants can be used in expressions ----
    const halfPi = Pi / 2
    const doubleMax = MaxPlayers * 2

    fmt.Println("Half Pi:", halfPi)
    fmt.Println("Double Max:", doubleMax)
}

